SELECT subreddit_name, subscribers
FROM subreddits
ORDER BY subscribers DESC;

SELECT upvotes
FROM content
WHERE content_id = 0;

SELECT text
FROM content
WHERE time = (SELECT MAX(time) FROM content);

SELECT subreddit_name
FROM subreddits
WHERE subscribers = (SELECT MAX(subscribers) FROM subreddits);

SELECT MAX(time) AS most_recent_time
FROM content
WHERE subreddit_id = (SELECT subreddit_id FROM subreddits WHERE subreddit_name = 'rareinsults');

SELECT upvotes + downvotes AS total_votes
FROM content
WHERE content_id = 1;

SELECT upvotes
FROM content
ORDER BY upvotes DESC;
